// Aggregate invoice data from the first input
const invoices = $input.all()[0]?.json ? 
  $input.all().map(item => item.json) : [];

// Get expense data passed from Set node
const expensesRaw = $('List Expenses').all();
const expenses = expensesRaw.map(e => e.json);

// Revenue calculations
const totalRevenue = invoices.reduce((sum, inv) => sum + (inv.total || 0), 0);
const taxCollected = invoices.reduce((sum, inv) => sum + (inv.taxAmount || (inv.total - inv.subtotal) || 0), 0);
const subtotalRevenue = invoices.reduce((sum, inv) => sum + (inv.subtotal || inv.total || 0), 0);

// Expense calculations
const totalExpenses = expenses.reduce((sum, exp) => sum + (exp.amount || 0), 0);
const taxPaid = expenses.reduce((sum, exp) => sum + (exp.taxAmount || 0), 0);

// Net calculations
const netVAT = taxCollected - taxPaid;
const netProfit = subtotalRevenue - totalExpenses;

// Invoice breakdown by status
const byStatus = invoices.reduce((acc, inv) => {
  const status = inv.status || 'unknown';
  acc[status] = (acc[status] || 0) + 1;
  return acc;
}, {});

const monthName = $('Calculate Date Range').item.json.monthName;
const period = $('Calculate Date Range').item.json.firstDayLastMonth + ' to ' + $('Calculate Date Range').item.json.lastDayLastMonth;

return [{
  json: {
    period,
    monthName,
    invoiceCount: invoices.length,
    expenseCount: expenses.length,
    totalRevenue: totalRevenue.toFixed(2),
    subtotalRevenue: subtotalRevenue.toFixed(2),
    taxCollected: taxCollected.toFixed(2),
    totalExpenses: totalExpenses.toFixed(2),
    taxPaid: taxPaid.toFixed(2),
    netVAT: netVAT.toFixed(2),
    netProfit: netProfit.toFixed(2),
    invoicesByStatus: JSON.stringify(byStatus),
    reportGeneratedAt: new Date().toISOString()
  }
}];
